#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, i;
    int *arr;

    printf("Enter array size: ");
    scanf("%d", &n);

    // Allocate memory for n integers
    arr = (int*)malloc(n * sizeof(int));

    // Check if allocation succeeded
    if (arr == NULL) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Initialize array elements
    for (i = 0; i < n; i++) {
        arr[i] = i * 10;  // or *(arr + i) = i * 10;
    }

    // Display array elements
    printf("Array elements: ");
    for (i = 0; i < n; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    // Free allocated memory
    free(arr);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int rows = 3, cols = 4;
    int **arr;
    int i, j;

    // Allocate array of row pointers
    arr = (int**)malloc(rows * sizeof(int*));
    if (arr == NULL) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Allocate each row
    for (i = 0; i < rows; i++) {
        arr[i] = (int*)malloc(cols * sizeof(int));
        if (arr[i] == NULL) {
            // Handle failure - free previously allocated
            for (j = 0; j < i; j++) {
                free(arr[j]);
            }
            free(arr);
            return 1;
        }
    }

    // Initialize and display elements
    for (i = 0; i < rows; i++) {
        for (j = 0; j < cols; j++) {
            arr[i][j] = i * cols + j;
        }
    }

    printf("2D Array:\n");
    for (i = 0; i < rows; i++) {
        for (j = 0; j < cols; j++) {
            printf("%3d ", arr[i][j]);
        }
        printf("\n");
    }

    // Free memory in reverse order
    for (i = 0; i < rows; i++) {
        free(arr[i]);
    }
    free(arr);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct {
    int *data;      // Pointer to array
    int size;       // Current number of elements
    int capacity;   // Total allocated slots
} DynamicArray;

// Initialize dynamic array
void init(DynamicArray *arr, int initial_capacity) {
    arr->data = (int*)malloc(initial_capacity * sizeof(int));
    arr->size = 0;
    arr->capacity = initial_capacity;
}

// Resize if needed
void ensureCapacity(DynamicArray *arr) {
    if (arr->size == arr->capacity) {
        int new_capacity = arr->capacity * 2;
        int *new_data = (int*)realloc(arr->data, new_capacity * sizeof(int));
        if (new_data == NULL) {
            printf("Memory allocation failed\n");
            return;
        }
        arr->data = new_data;
        arr->capacity = new_capacity;
        printf("Resized from %d to %d\n", arr->capacity/2, arr->capacity);
    }
}

// Add element at end
void pushBack(DynamicArray *arr, int value) {
    ensureCapacity(arr);
    arr->data[arr->size++] = value;
}

// Get element at index
int get(DynamicArray *arr, int index) {
    if (index >= 0 && index < arr->size) {
        return arr->data[index];
    }
    return -1;  // Error value
}

// Free memory
void destroy(DynamicArray *arr) {
    free(arr->data);
    arr->data = NULL;
    arr->size = arr->capacity = 0;
}

// Main function demonstrating usage
int main() {
    DynamicArray arr;
    init(&arr, 2);  // Start with capacity 2

    printf("Adding elements to dynamic array:\n");
    for (int i = 1; i <= 10; i++) {
        pushBack(&arr, i * 10);
    }

    printf("\nArray contents: ");
    for (int i = 0; i < arr.size; i++) {
        printf("%d ", arr.data[i]);
    }
    printf("\nSize: %d, Capacity: %d\n", arr.size, arr.capacity);

    destroy(&arr);
    return 0;
}
